const input = $items("Set Input Defaults")[0].json;
const fetchRes = $items("Fetch Existing Entities")[0].json;
let existingClasses = [];
let existingProperties = [];
let existingRules = [];
try {
  const results = fetchRes.results || [];
  if (results[0] && results[0].data) {
    for (const d of results[0].data) {
      const row = d.row;
      if (row[0] === 'Class') {
        existingClasses.push({ iri: row[1], label: row[2] });
      } else {
        existingProperties.push({ type: row[0], iri: row[1], swrl_label: row[3] || row[2], range: row[4] });
      }
    }
  }
  if (results[1] && results[1].data) {
    for (const d of results[1].data) {
      existingRules.push({ rule_id: d.row[0], text: d.row[1], kind: d.row[2] });
    }
  }
} catch (e) {}
const entityLines = [];
if (existingClasses.length || existingProperties.length || existingRules.length) {
  entityLines.push('EXISTING ENTITIES IN THE GRAPH (you MUST reuse these, do NOT create duplicates):');
  if (existingClasses.length) {
    entityLines.push('Classes:');
    existingClasses.forEach(c => entityLines.push('  - ' + c.label + ' (iri: ' + c.iri + ')'));
  }
  if (existingProperties.length) {
    entityLines.push('Properties:');
    existingProperties.forEach(p => entityLines.push('  - ' + p.swrl_label + ' [' + p.type + '] (iri: ' + p.iri + ', range: ' + p.range + ')'));
  }
  if (existingRules.length) {
    entityLines.push('Existing Rules:');
    existingRules.forEach(r => entityLines.push('  - ' + r.rule_id + ' (' + r.kind + '): ' + r.text));
  }
}
const existingEntitiesSection = entityLines.join('\n');
const rulesText = (input.rules_text || '')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();
if (!rulesText) {
  throw new Error('rules_text is required');
}
const editPat = /\b(?:edit|update|change|modify|set|increase|decrease|raise|lower|adjust)\b/i;
const ruleIdPat = /(?:Rule_Id|rule[_ ]?id)\s*[:=\s]*\W*([A-Z_][A-Z0-9_]+)/gi;
const isEditPrompt = editPat.test(rulesText);
const editRuleIds = [];
let ruleIdMatch;
while ((ruleIdMatch = ruleIdPat.exec(rulesText)) !== null) { editRuleIds.push(ruleIdMatch[1]); }

// Smart edit detection: match prompt keywords against existing rules
if (isEditPrompt && editRuleIds.length === 0 && existingRules.length > 0) {
  const stopWords = new Set(['the','a','an','to','of','in','for','and','or','is','are','be','must','should','each','every','all','at','least','most','with','have','has','it','that','this','from','by','on','not','also','rule','rules','new','minimum','maximum','edit','update','change','modify','set','increase','decrease','raise','lower','adjust','now','per','need','needs','make','no','more','than','less','into']);
  const promptWords = rulesText.toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(w => w.length > 2 && !stopWords.has(w));
  const scored = [];
  for (const rule of existingRules) {
    const haystack = (rule.rule_id + ' ' + rule.text).toLowerCase();
    let hits = 0;
    for (const w of promptWords) {
      if (haystack.includes(w)) hits++;
    }
    if (hits > 0) scored.push({ id: rule.rule_id, hits });
  }
  scored.sort((a, b) => b.hits - a.hits);
  if (scored.length > 0) {
    const best = scored[0].hits;
    scored.filter(s => s.hits === best).forEach(s => editRuleIds.push(s.id));
  }
}
const editRuleId = isEditPrompt && editRuleIds.length ? editRuleIds[0] : null;
const project = input.project_name || 'default-project';
const fewShot = [
  'Example input: "Maximum height of each building must be at most 75 m."',
  'Example output:',
  '',
  "MERGE (C_Building:Class {iri: 'ex:Building'})",
  "SET C_Building.label = 'Building', C_Building.project = '" + project + "', C_Building.graph = 'OntoGraph'",
  '',
  "MERGE (DP_H:DatatypeProperty {iri: 'ex:hasHeightM'})",
  "SET DP_H.SWRL_label = 'hasHeightM', DP_H.range = 'xsd:decimal', DP_H.project = '" + project + "', DP_H.graph = 'OntoGraph'",
  '',
  "MERGE (B_gt:Builtin {iri: 'swrlb:greaterThan'})",
  "SET B_gt.label = 'greaterThan', B_gt.project = '" + project + "', B_gt.graph = 'Metagraph'",
  '',
  "MERGE (DP_V:DatatypeProperty {iri: 'ex:violatesMaxHeight'})",
  "SET DP_V.SWRL_label = 'violatesMaxHeight', DP_V.range = 'xsd:boolean', DP_V.project = '" + project + "', DP_V.graph = 'OntoGraph'",
  '',
  "MERGE (r:Rule {Rule_Id: 'R_URB_HEIGHT_MAX_75_V'})",
  "SET r.text = 'Building(?b)^hasHeightM(?b,?h)^swrlb:greaterThan(?h,75)->violatesMaxHeight(?b,true)', r.kind = 'violation', r.project = '" + project + "', r.graph = 'Metagraph'",
  '',
  "MERGE (vb:Var {name: '?b'}) SET vb.project = '" + project + "', vb.graph = 'Metagraph'",
  "MERGE (vh:Var {name: '?h'}) SET vh.project = '" + project + "', vh.graph = 'Metagraph'",
  "MERGE (lit75:Literal {lex: '75', datatype: 'xsd:decimal'}) SET lit75.project = '" + project + "', lit75.graph = 'Metagraph'",
  "MERGE (litT:Literal {lex: 'true', datatype: 'xsd:boolean'}) SET litT.project = '" + project + "', litT.graph = 'Metagraph'",
  '',
  "MERGE (a1:Atom {Atom_Id: 'R_URB_HEIGHT_MAX_75_V_A1'})",
  "SET a1.type = 'ClassAtom', a1.iri = 'ex:Building', a1.SWRL_label = 'Building', a1.project = '" + project + "', a1.graph = 'Metagraph'",
  "MERGE (a2:Atom {Atom_Id: 'R_URB_HEIGHT_MAX_75_V_A2'})",
  "SET a2.type = 'DataPropertyAtom', a2.iri = 'ex:hasHeightM', a2.SWRL_label = 'hasHeightM', a2.project = '" + project + "', a2.graph = 'Metagraph'",
  "MERGE (a3:Atom {Atom_Id: 'R_URB_HEIGHT_MAX_75_V_A3'})",
